    93	typedef struct m3ap_register_mce_req_s {
    94	  /* Unique eNB_id to identify the eNB within EPC.
    95	   * For macro eNB ids this field should be 20 bits long.
    96	   * For home eNB ids this field should be 28 bits long.
    97	   */
    98	  uint32_t MCE_id;
    99	  /* The type of the cell */
   100	  enum cell_type_e cell_type;
   101	
   102	  /* Optional name for the cell
   103	   * NOTE: the name can be NULL (i.e no name) and will be cropped to 150
   104	   * characters.
   105	   */
