   107	
   108	  /* Tracking area code */
   109	  uint16_t tac;
   110	
   111	  /* Mobile Country Code
   112	   * Mobile Network Code
   113	   */
   114	  uint16_t mcc;
   115	  uint16_t mnc;
   116	  uint8_t  mnc_digit_length;
   117	
   118	  /*
   119	   * CC Params
   120	   */
   121	  int16_t                 eutra_band[MAX_NUM_CCs];
   122	  uint32_t                downlink_frequency[MAX_NUM_CCs];
   123	  int32_t                 uplink_frequency_offset[MAX_NUM_CCs];
   124	  uint32_t                Nid_cell[MAX_NUM_CCs];
   125	  int16_t                 N_RB_DL[MAX_NUM_CCs];
   126	  frame_type_t            frame_type[MAX_NUM_CCs];
   127	  uint32_t                fdd_earfcn_DL[MAX_NUM_CCs];
   128	  uint32_t                fdd_earfcn_UL[MAX_NUM_CCs];
   129	  int                     num_cc;
   130	
   131	  /* To be considered for TDD */
   132	  //uint16_t tdd_EARFCN;
   133	  //uint16_t tdd_Transmission_Bandwidth;
   134	
   135	  /* The local eNB IP address to bind */
   136	  net_ip_address_t mme_m3_ip_address;
   137	
   138	  /* Nb of MME to connect to */
   139	  uint8_t          nb_m3;
   140	
   141	  /* List of target eNB to connect to for M3*/
   142	  net_ip_address_t target_mme_m3_ip_address[M3AP_MAX_NB_MCE_IP_ADDRESS];
   143	
   144	  /* Number of SCTP streams used for associations */
   145	  uint16_t sctp_in_streams;
   146	  uint16_t sctp_out_streams;
   147	
   148	  /* eNB port for M3C*/
   149	  uint32_t mme_port_for_M3C;
   150	
   151	  /* timers (unit: millisecond) */
   152	  int t_reloc_prep;
   153	  int tm3_reloc_overall;
   154	
   155	  /* Nb of MME to connect to */
   156	  uint8_t          nb_mme;
   157	  /* List of MME to connect to */
   158	  net_ip_address_t mme_ip_address[M3AP_MAX_NB_MME_IP_ADDRESS];
   159	} m3ap_register_mce_req_t;
