  DevAssert(pdu != NULL);

  container = &pdu->choice.initiatingMessage.value.choice.MBMSSessionStartRequest;

  /* MBMS Session Start Request == Non UE-related procedure -> stream 0 */
  if (stream != 0) {
    LOG_W(M3AP, "[SCTP %d] Received MBMS session start request on stream != 0 (%d)\n",
              assoc_id, stream);
  }

  message_p = itti_alloc_new_message(TASK_M3AP_MCE, 0, M3AP_MBMS_SESSION_START_REQ);
  DevAssert(message_p != NULL);

  /* Initialize the message structure */
  memset(&M3AP_MBMS_SESSION_START_REQ(message_p), 0, sizeof(m3ap_session_start_req_t));

  /* Extract MME-MBMS-M3AP-ID (Mandatory) */
  M3AP_FIND_PROTOCOLIE_BY_ID(M3AP_MBMSSessionStartRequest_Ies_t, ie, container, M3AP_ProtocolIE_ID_id_MME_MBMS_M3AP_ID, true);
  if (ie) {
    M3AP_MBMS_SESSION_START_REQ(message_p).mme_mbms_m3ap_id = ie->value.choice.MME_MBMS_M3AP_ID;
    LOG_D(M3AP, "Extracted MME-MBMS-M3AP-ID: %lu\n", M3AP_MBMS_SESSION_START_REQ(message_p).mme_mbms_m3ap_id);
  }

