  M3AP_FIND_PROTOCOLIE_BY_ID(M3AP_MBMSSessionStartRequest_Ies_t, ie, container, M3AP_ProtocolIE_ID_id_TMGI, true);
  if (ie) {
    /* Extract PLMN from TMGI */
    TBCD_TO_MCC_MNC(&ie->value.choice.TMGI.pLMNidentity,
                    M3AP_MBMS_SESSION_START_REQ(message_p).mcc,
                    M3AP_MBMS_SESSION_START_REQ(message_p).mnc,
                    M3AP_MBMS_SESSION_START_REQ(message_p).mnc_digit_length);

    /* Extract Service ID from TMGI */
    M3AP_MBMS_SESSION_START_REQ(message_p).service_id = 
      ((ie->value.choice.TMGI.serviceID.buf[0] << 16) | 
       (ie->value.choice.TMGI.serviceID.buf[1] << 8) | 
       (ie->value.choice.TMGI.serviceID.buf[2]));

    LOG_D(M3AP, "Extracted TMGI - MCC: %d, MNC: %d, Service ID: %lu\n",
          M3AP_MBMS_SESSION_START_REQ(message_p).mcc,
          M3AP_MBMS_SESSION_START_REQ(message_p).mnc,
          M3AP_MBMS_SESSION_START_REQ(message_p).service_id);
  }

  /* Extract MBMS-Session-ID (Optional) */
  M3AP_FIND_PROTOCOLIE_BY_ID(M3AP_MBMSSessionStartRequest_Ies_t, ie, container, M3AP_ProtocolIE_ID_id_MBMS_Session_ID, false);
  if (ie) {
    M3AP_MBMS_SESSION_START_REQ(message_p).mbms_session_id_present = 1;
    M3AP_MBMS_SESSION_START_REQ(message_p).mbms_session_id = ie->value.choice.MBMS_Session_ID;
    LOG_D(M3AP, "Extracted MBMS-Session-ID: %lu\n", M3AP_MBMS_SESSION_START_REQ(message_p).mbms_session_id);
  }

  /* Extract MBMS-E-RAB-QoS-Parameters (Mandatory) */
  M3AP_FIND_PROTOCOLIE_BY_ID(M3AP_MBMSSessionStartRequest_Ies_t, ie, container, M3AP_ProtocolIE_ID_id_MBMS_E_RAB_QoS_Parameters, true);
  if (ie) {
    M3AP_MBMS_E_RAB_QoS_Parameters_t *qos_params = &ie->value.choice.MBMS_E_RAB_QoS_Parameters;

    /* Extract QCI */
    M3AP_MBMS_SESSION_START_REQ(message_p).qci = qos_params->qCI;

    /* Extract Allocation and Retention Priority if present */
    if (qos_params->allocationAndRetentionPriority) {
      M3AP_AllocationAndRetentionPriority_t *arp = qos_params->allocationAndRetentionPriority;

      /* Priority Level */
      if (arp->priorityLevel) {
        M3AP_MBMS_SESSION_START_REQ(message_p).priority_level_present = 1;
        M3AP_MBMS_SESSION_START_REQ(message_p).priority_level = *arp->priorityLevel;
      }

      /* Pre-emption Capability */
      if (arp->pre_emptionCapability) {
        M3AP_MBMS_SESSION_START_REQ(message_p).pre_emption_capability_present = 1;
        M3AP_MBMS_SESSION_START_REQ(message_p).pre_emption_capability = *arp->pre_emptionCapability;
      }

      /* Pre-emption Vulnerability */
      if (arp->pre_emptionVulnerability) {
        M3AP_MBMS_SESSION_START_REQ(message_p).pre_emption_vulnerability_present = 1;
        M3AP_MBMS_SESSION_START_REQ(message_p).pre_emption_vulnerability = *arp->pre_emptionVulnerability;
      }
    }

    LOG_D(M3AP, "Extracted MBMS-E-RAB-QoS-Parameters - QCI: %lu\n", M3AP_MBMS_SESSION_START_REQ(message_p).qci);
  }

  /* Extract MBMS-Session-Duration (Mandatory) */
  M3AP_FIND_PROTOCOLIE_BY_ID(M3AP_MBMSSessionStartRequest_Ies_t, ie, container, M3AP_ProtocolIE_ID_id_MBMS_Session_Duration, true);
  if (ie) {
    M3AP_MBMS_SESSION_START_REQ(message_p).mbms_session_duration = ie->value.choice.MBMS_Session_Duration;
    LOG_D(M3AP, "Extracted MBMS-Session-Duration: %lu seconds\n", M3AP_MBMS_SESSION_START_REQ(message_p).mbms_session_duration);
  }

  /* Extract MBMS-Service-Area (Mandatory) */
  M3AP_FIND_PROTOCOLIE_BY_ID(M3AP_MBMSSessionStartRequest_Ies_t, ie, container, M3AP_ProtocolIE_ID_id_MBMS_Service_Area, true);
  if (ie) {
    M3AP_MBMS_Service_Area_t *service_area = &ie->value.choice.MBMS_Service_Area;
    M3AP_MBMS_SESSION_START_REQ(message_p).num_mbms_service_area = service_area->list.count;

    for (i = 0; i < service_area->list.count && i < 32; i++) {
      M3AP_MBMS_SESSION_START_REQ(message_p).mbms_service_area_id[i] = *service_area->list.array[i];
    }

    LOG_D(M3AP, "Extracted MBMS-Service-Area with %d service area IDs\n", M3AP_MBMS_SESSION_START_REQ(message_p).num_mbms_service_area);
  }

  /* Extract MinimumTimeToMBMSDataTransfer (Mandatory) */
  M3AP_FIND_PROTOCOLIE_BY_ID(M3AP_MBMSSessionStartRequest_Ies_t, ie, container, M3AP_ProtocolIE_ID_id_MinimumTimeToMBMSDataTransfer, true);
  if (ie) {
    M3AP_MBMS_SESSION_START_REQ(message_p).minimum_time_to_mbms_data_transfer = ie->value.choice.MinimumTimeToMBMSDataTransfer;
    LOG_D(M3AP, "Extracted MinimumTimeToMBMSDataTransfer: %lu seconds\n", 
          M3AP_MBMS_SESSION_START_REQ(message_p).minimum_time_to_mbms_data_transfer);
  }

  /* Extract TNL-Information (Mandatory) */
  M3AP_FIND_PROTOCOLIE_BY_ID(M3AP_MBMSSessionStartRequest_Ies_t, ie, container, M3AP_ProtocolIE_ID_id_TNL_Information, true);
  if (ie) {
    M3AP_TNL_Information_t *tnl_info = &ie->value.choice.TNL_Information;
    M3AP_MBMS_SESSION_START_REQ(message_p).num_tnl_info = tnl_info->list.count;

    for (i = 0; i < tnl_info->list.count && i < 8; i++) {
      M3AP_TNLInformation_Item_t *tnl_item = tnl_info->list.array[i];

      /* Extract Transport Layer Address */
      if (tnl_item->tNLAddress.size == 4) {
        /* IPv4 address */
        M3AP_MBMS_SESSION_START_REQ(message_p).tnl_info[i].ipv4 = 1;
        M3AP_MBMS_SESSION_START_REQ(message_p).tnl_info[i].ipv6 = 0;
        inet_ntop(AF_INET, tnl_item->tNLAddress.buf, 
                  M3AP_MBMS_SESSION_START_REQ(message_p).tnl_info[i].ipv4_address, 
                  sizeof(M3AP_MBMS_SESSION_START_REQ(message_p).tnl_info[i].ipv4_address));
      } else if (tnl_item->tNLAddress.size == 16) {
        /* IPv6 address */
        M3AP_MBMS_SESSION_START_REQ(message_p).tnl_info[i].ipv4 = 0;
        M3AP_MBMS_SESSION_START_REQ(message_p).tnl_info[i].ipv6 = 1;
        inet_ntop(AF_INET6, tnl_item->tNLAddress.buf, 
                  M3AP_MBMS_SESSION_START_REQ(message_p).tnl_info[i].ipv6_address, 
                  sizeof(M3AP_MBMS_SESSION_START_REQ(message_p).tnl_info[i].ipv6_address));
      }
    }

    LOG_D(M3AP, "Extracted TNL-Information with %d entries\n", M3AP_MBMS_SESSION_START_REQ(message_p).num_tnl_info);
  }

  /* Extract Time-ofMBMS-DataTransfer (Optional) */
  M3AP_FIND_PROTOCOLIE_BY_ID(M3AP_MBMSSessionStartRequest_Ies_t, ie, container, M3AP_ProtocolIE_ID_id_Time_ofMBMS_DataTransfer, false);
  if (ie) {
    M3AP_MBMS_SESSION_START_REQ(message_p).time_of_mbms_data_transfer_present = 1;
    LOG_D(M3AP, "Extracted Time-ofMBMS-DataTransfer\n");
  }

  /* Extract Reestablishment (Optional) */
  M3AP_FIND_PROTOCOLIE_BY_ID(M3AP_MBMSSessionStartRequest_Ies_t, ie, container, M3AP_ProtocolIE_ID_id_Reestablishment, false);
  if (ie) {
    M3AP_MBMS_SESSION_START_REQ(message_p).reestablishment_present = 1;
    M3AP_MBMS_SESSION_START_REQ(message_p).reestablishment = ie->value.choice.Reestablishment;
    LOG_D(M3AP, "Extracted Reestablishment: %lu\n", M3AP_MBMS_SESSION_START_REQ(message_p).reestablishment);
  }

  /* Extract Alternative-TNL-Information (Optional) */
  M3AP_FIND_PROTOCOLIE_BY_ID(M3AP_MBMSSessionStartRequest_Ies_t, ie, container, M3AP_ProtocolIE_ID_id_Alternative_TNL_Information, false);
  if (ie) {
    M3AP_TNL_Information_t *alt_tnl_info = &ie->value.choice.Alternative_TNL_Information;
    M3AP_MBMS_SESSION_START_REQ(message_p).num_alternative_tnl_info = alt_tnl_info->list.count;

    for (i = 0; i < alt_tnl_info->list.count && i < 8; i++) {
      M3AP_TNLInformation_Item_t *tnl_item = alt_tnl_info->list.array[i];

      if (tnl_item->tNLAddress.size == 4) {
        /* IPv4 address */
        M3AP_MBMS_SESSION_START_REQ(message_p).alternative_tnl_info[i].ipv4 = 1;
        M3AP_MBMS_SESSION_START_REQ(message_p).alternative_tnl_info[i].ipv6 = 0;
        inet_ntop(AF_INET, tnl_item->tNLAddress.buf, 
                  M3AP_MBMS_SESSION_START_REQ(message_p).alternative_tnl_info[i].ipv4_address, 
                  sizeof(M3AP_MBMS_SESSION_START_REQ(message_p).alternative_tnl_info[i].ipv4_address));
      } else if (tnl_item->tNLAddress.size == 16) {
        /* IPv6 address */
        M3AP_MBMS_SESSION_START_REQ(message_p).alternative_tnl_info[i].ipv4 = 0;
        M3AP_MBMS_SESSION_START_REQ(message_p).alternative_tnl_info[i].ipv6 = 1;
        inet_ntop(AF_INET6, tnl_item->tNLAddress.buf, 
                  M3AP_MBMS_SESSION_START_REQ(message_p).alternative_tnl_info[i].ipv6_address, 
                  sizeof(M3AP_MBMS_SESSION_START_REQ(message_p).alternative_tnl_info[i].ipv6_address));
      }
    }

    LOG_D(M3AP, "Extracted Alternative-TNL-Information with %d entries\n", M3AP_MBMS_SESSION_START_REQ(message_p).num_alternative_tnl_info);
  }

  /* Extract MBMS-Cell-List (Optional) */
  M3AP_FIND_PROTOCOLIE_BY_ID(M3AP_MBMSSessionStartRequest_Ies_t, ie, container, M3AP_ProtocolIE_ID_id_MBMS_Cell_List, false);
  if (ie) {
    M3AP_MBMS_Cell_List_t *cell_list = &ie->value.choice.MS_Cell_List;
    M3AP_MBMS_SESSION_START_REQ(message_p).num_mbms_cell_list = cell_list->list.count;

    for (i = 0; i < cell_list->list.count && i < 256; i++) {
      M3AP_ECGI_t *ecgi = cell_list->list.array[i];
      M3AP_MBMS_SESSION_START_REQ(message_p).mbms_cell_list[i].cell_id = ecgi->eUTRANcellIdentifier.buf[0];
    }

    LOG_D(M3AP, "Extracted MBMS-Cell-List with %d cells\n", M3AP_MBMS_SESSION_START_REQ(message_p).num_mbms_cell_list);
  }

  /* Send message to MCE APP */
  itti_send_msg_to_task(TASK_MCE_APP, ENB_MODULE_ID_TO_INSTANCE(instance), message_p);

  LOG_I(M3AP, "Successfully processed MBMS Session Start Request from assoc_id %d\n", assoc_id);

  return 0;
}"} <|tool_call_end|> <|tool_calls_section_end|>

